import os
import pandas as pd
from tensorflow.keras.preprocessing.image import ImageDataGenerator
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Conv2D, MaxPooling2D, Flatten, Dense

def load_csv(file_path):
    try:
        data = pd.read_csv(file_path)
        return data
    except Exception as e:
        print(f"Error loading CSV file: {str(e)}")
        return None

def train_model(model_name, training_data, validation_data, image_size):
    # Data augmentation using ImageDataGenerator
    datagen = ImageDataGenerator(rescale=1./255,
                                 shear_range=0.2,
                                 zoom_range=0.2,
                                 horizontal_flip=True)
    
    model = Sequential()
    model.add(Conv2D(32, (3, 3), activation='relu', input_shape=(image_size, image_size, 3)))
    model.add(MaxPooling2D((2, 2)))
    model.add(Conv2D(64, (3, 3), activation='relu'))
    model.add(MaxPooling2D((2, 2)))
    model.add(Conv2D(128, (3, 3), activation='relu'))
    model.add(Flatten())
    model.add(Dense(128, activation='relu'))
    model.add(Dense(10, activation='softmax'))
    
    model.compile(optimizer='adam',
                  loss='sparse_categorical_crossentropy',
                  metrics=['accuracy'])
    
    train_datagen = datagen.flow_from_dataframe(training_data,
                                                x_col='filename',
                                                y_col='label',
                                                target_size=image_size,
                                                batch_size=32)
    
    validation_datagen = datagen.flow_from_dataframe(validation_data,
                                                     x_col='filename',
                                                     y_col='label',
                                                     target_size=image_size,
                                                     batch_size=32)
    
    history = model.fit(train_datagen,
                        epochs=10,
                        validation_data=validation_datagen)
    
    return model, history

def train_model_from_csv(csv_file_path, model_name):
    training_data = load_csv(csv_file_path)
    if training_data is not None:
        # Assuming CSV file has 'filename' and 'label' columns
        image_size = 224  # Replace with actual image size
        validation_split = 0.2
        
        # Split data into training and validation sets
        from sklearn.model_selection import train_test_split
        train_data, val_data = train_test_split(training_data, test_size=validation_split)
        
        model, history = train_model(model_name,
                                    train_data[['filename', 'label']].to_dict(orient='records'),
                                    val_data[['filename', 'label']].to_dict(orient='records'),
                                    image_size)
        
        # Save the trained model
        model.save(f'{model_name}.h5')
        
        return history

def contribute_training_examples(user_file_paths):
    for file_path in user_file_paths:
        try:
            training_data = pd.read_csv(file_path)
            train_model_from_csv(file_path, 'user_contributed_model')
        except Exception as e:
            print(f"Error contributing training examples: {str(e)}")

# Usage
csv_file_path = input("Enter CSV file path: ")
contribute_training_examples([csv_file_path])